import '../FeedbackSendButton/FeedbackSendButton.scss'

const FeedbackSendButton = ({ onClick, cooldownTime = 0 }) => {
    const getButtonText = () => {
        if (cooldownTime > 0) {
            return 'Отправлено';
        }
        return 'Отправить';
    };

    return(
        <button 
            className={`feedbackSendButton ${cooldownTime > 0 ? 'sent' : ''}`} 
            onClick={onClick} 
            disabled={cooldownTime > 0}
        >
            {getButtonText()}
        </button>
    )
}

export default FeedbackSendButton;